INSERT INTO `studies` (`id`, `title`, `description`, `file_path`, `congregation_id`, `created_at`) VALUES ('4', 'Devocional de Consagração Meu Ano em Tuas Mãos', 'O livro “Devocional de Consagração: Meu Ano em Tuas Mãos” é um guia espiritual preparado para quem deseja dedicar cada dia do ano ao Senhor. Com reflexões diárias, mensagens bíblicas e momentos de oração, o devocional conduz o leitor a uma vida de maior intimidade com Deus, incentivando a entrega, a fé e a dependência total da Sua vontade.\r\n\r\nIdeal para fortalecer a caminhada cristã, a obra convida o leitor a começar e viver o ano colocando seus planos, sonhos e decisões nas mãos de Deus, buscando direção, renovação e crescimento espiritual contínuo.', '69bb0c3766a2e.pdf', NULL, '2026-03-18 17:33:59');
INSERT INTO `studies` (`id`, `title`, `description`, `file_path`, `congregation_id`, `created_at`) VALUES ('5', 'A Importância da Escola Bíblica ', 'A Escola Bíblica é fundamental para o crescimento espiritual do cristão, pois proporciona um ensino sistemático da Palavra de Deus. É nesse ambiente que aprendemos mais profundamente as Escrituras, fortalecemos a fé e desenvolvemos entendimento para viver de acordo com os princípios bíblicos.\r\n\r\nAlém disso, a Escola Bíblica promove comunhão, edificação e preparo para a vida cristã, ajudando crianças, jovens e adultos a crescerem no conhecimento e na prática da verdade. É um espaço de aprendizado, transformação e fortalecimento da igreja como corpo de Cristo.', '69bb0c6dd59ea.pdf', NULL, '2026-03-18 17:34:53');
INSERT INTO `studies` (`id`, `title`, `description`, `file_path`, `congregation_id`, `created_at`) VALUES ('6', 'Estudo Bíblico 1', 'Descrição do estudo 1', 'mock_study.pdf', '4', '2026-03-20 19:32:06');
